// Example: Sales analysis by category
db.orders.aggregate([
 // Stage 1: Filter recent orders
 {
 $match: {
 orderDate: { $gte: ISODate("2024-01-01") },
 status: "completed"
 }
 },
 // Stage 2: Unwind products array
 { $unwind: "$products" },
 // Stage 3: Group by category and calculate totals
 {
 $group: {
 _id: "$products.category",
 totalRevenue: { $sum: { $multiply: ["$products.price", "$products.quantity"] } },
 orderCount: { $sum: 1 }
 }
 },
 // Stage 4: Sort by revenue descending
 { $sort: { totalRevenue: -1 } },
 // Stage 5: Project final output
 {
 $project: {
 category: "$_id",
 totalRevenue: 1,
 orderCount: 1,
 _id: 0
 }
 }
]);

